#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main()
{
    char str[100];
    char *ptr;
    int cnt = 2;

    while(1)
    {
        printf(\"입력:\");
        scanf(\"%s\", str);
        ptr = (char*)malloc(strlen(str) + 1);
        strcpy(ptr, str);
        printf(\"%d번 출력:\", cnt);
        for (int i = strlen(ptr) - 1; i >= 0; i--)
        {
            printf(\"%c\", ptr[i]);
        }
        if (cnt <= 1)
            break;
        else
            cnt--;
        printf(\"\\n\");
    }
    return 0;
}

